const out = [];
for (const item of $input.all()) {
  const d = item.json.body && item.json.body.event_data;
  if (!d) continue;
  const hasLabel = Array.isArray(d.labels) && d.labels.includes('Google Calendar');
  const hasDue = d.due && (d.due.date || d.due.datetime);
  if (hasLabel && hasDue) out.push({ json: item.json });
}
return out;

const task = $input.item.json.body.event_data;
const due = task.due || {};
const hasTime = !!due.datetime;
const startISO = hasTime ? due.datetime : `${due.date}T09:00:00`;
const start = new Date(startISO);
let durationMin = 60;
if (task.duration && task.duration.amount) {
  durationMin = task.duration.unit === 'day' ? task.duration.amount * 24 * 60 : task.duration.amount;
}
const end = new Date(start.getTime() + durationMin * 60 * 1000);
const desc = (task.description ? task.description + '\n\n' : '') + 'Synced from Todoist: ' + (task.url || `https://todoist.com/showTask?id=${task.id}`);
const newLabels = (task.labels || []).filter(l => l !== 'Google Calendar');
return {
  json: {
    taskId: task.id,
    summary: task.content,
    description: desc,
    start: start.toISOString(),
    end: end.toISOString(),
    newLabels
  }
};
